import AsyncStorage from '@react-native-async-storage/async-storage';

const BASE_URL = 'https://api.example.com';
const AUTH_TOKEN_KEY = 'authToken';

// Helper to get the authentication token from storage
const getAuthToken = async () => {
  return await AsyncStorage.getItem(AUTH_TOKEN_KEY);
};

// Helper to set or remove the authentication token in storage
const setAuthToken = async (token) => {
  if (token) {
    await AsyncStorage.setItem(AUTH_TOKEN_KEY, token);
  } else {
    await AsyncStorage.removeItem(AUTH_TOKEN_KEY);
  }
};

// Generic request helper function
const request = async (endpoint, method = 'GET', data = null, authenticated = true) => {
  const url = `${BASE_URL}${endpoint}`;
  const headers = {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
  };

  if (authenticated) {
    const token = await getAuthToken();
    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    } else {
      // If authentication is required but no token is found, throw an error
      // or return a specific unauthenticated status
      throw new Error('Authentication required, but no token found.');
    }
  }

  const config = {
    method,
    headers,
  };

  if (data && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
    config.body = JSON.stringify(data);
  }

  try {
    const response = await fetch(url, config);

    if (!response.ok) {
      let errorData = null;
      try {
        errorData = await response.json();
      } catch (jsonError) {
        // If response is not JSON, use status text
        errorData = { message: response.statusText || 'An unknown error occurred.' };
      }
      throw new Error(errorData.message || response.statusText || 'API request failed');
    }

    // Handle 204 No Content responses which don't have a body
    if (response.status === 204) {
      return null;
    }

    return await response.json();
  } catch (error) {
    console.error(`API request to ${url} failed:`, error);
    throw error; // Re-throw to allow calling components to handle it
  }
};

